/**
 * Validation helper module.
 *
 * Each exported function returns an array of error message strings.
 * An empty array means the input passed all checks.
 */

/** Basic email regex (RFC 5321 practical subset). */
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user ID coming from a route parameter.
 * @param {string} rawId - The raw string value from req.params.id.
 * @returns {string[]} Array of validation error messages.
 */
function validateUserId(rawId) {
  const errors = [];
  if (rawId === undefined || rawId === null || rawId === '') {
    errors.push('id is required');
    return errors;
  }
  const num = Number(rawId);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }
  return errors;
}

/**
 * Validate the body fields expected when creating a user (all required).
 * @param {object} body - Request body object.
 * @returns {string[]} Array of validation error messages.
 */
function validateCreateUser(body) {
  const errors = [];

  // ----- name -----
  if (body.name === undefined || body.name === null) {
    errors.push('name is required');
  } else if (typeof body.name !== 'string') {
    errors.push('name must be a string');
  } else if (body.name.trim().length < 1) {
    errors.push('name must be at least 1 character');
  } else if (body.name.length > 100) {
    errors.push('name must not exceed 100 characters');
  }

  // ----- email -----
  if (body.email === undefined || body.email === null) {
    errors.push('email is required');
  } else if (typeof body.email !== 'string') {
    errors.push('email must be a string');
  } else if (body.email.length > 254) {
    errors.push('email must not exceed 254 characters');
  } else if (!EMAIL_RE.test(body.email)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate the body fields expected when updating a user.
 * At least one field must be present; present fields must pass type/length rules.
 * @param {object} body - Request body object.
 * @returns {string[]} Array of validation error messages.
 */
function validateUpdateUser(body) {
  const errors = [];

  const hasName = body.name !== undefined && body.name !== null;
  const hasEmail = body.email !== undefined && body.email !== null;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name, email) must be provided');
    return errors;
  }

  // ----- name (if provided) -----
  if (hasName) {
    if (typeof body.name !== 'string') {
      errors.push('name must be a string');
    } else if (body.name.trim().length < 1) {
      errors.push('name must be at least 1 character');
    } else if (body.name.length > 100) {
      errors.push('name must not exceed 100 characters');
    }
  }

  // ----- email (if provided) -----
  if (hasEmail) {
    if (typeof body.email !== 'string') {
      errors.push('email must be a string');
    } else if (body.email.length > 254) {
      errors.push('email must not exceed 254 characters');
    } else if (!EMAIL_RE.test(body.email)) {
      errors.push('email must be a valid email address');
    }
  }

  return errors;
}

module.exports = { validateUserId, validateCreateUser, validateUpdateUser };

