const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user `id` supplied as a URL path parameter (always a string
 * coming from Express).  Must be a whole positive number.
 *
 * @param {string} value - raw path-param value
 * @returns {string[]} validation errors
 */
function validateId(value) {
  const errors = [];
  const num = Number(value);
  if (value === undefined || value === null || value === '') {
    errors.push('id is required');
  } else if (!Number.isInteger(num) || num <= 0) {
    errors.push('id must be a positive integer');
  }
  return errors;
}

/**
 * Validate a `name` field from a request body.
 *
 * Rules:
 *  - required (unless `optional` flag is set)
 *  - must be a string
 *  - length 1–100 characters
 *
 * @param {*}       value    - value to validate
 * @param {boolean} optional - when true, undefined/null values are accepted
 * @returns {string[]} validation errors
 */
function validateName(value, optional = false) {
  const errors = [];

  if (value === undefined || value === null) {
    if (!optional) errors.push('name is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  if (value.length < 1) {
    errors.push('name must be at least 1 character long');
  } else if (value.length > 100) {
    errors.push('name must be at most 100 characters long');
  }

  return errors;
}

/**
 * Validate an `email` field from a request body.
 *
 * Rules:
 *  - required (unless `optional` flag is set)
 *  - must be a string
 *  - must match a basic email format
 *  - length ≤ 254 characters (RFC 5321 maximum)
 *
 * @param {*}       value    - value to validate
 * @param {boolean} optional - when true, undefined/null values are accepted
 * @returns {string[]} validation errors
 */
function validateEmail(value, optional = false) {
  const errors = [];

  if (value === undefined || value === null) {
    if (!optional) errors.push('email is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (value.length > 254) {
    errors.push('email must be at most 254 characters long');
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

/**
 * Validate the body of a POST /users request (all fields required).
 *
 * @param {object} body - parsed request body
 * @returns {string[]} all validation errors found
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name),
    ...validateEmail(body.email),
  ];
}

/**
 * Validate the body of a PUT /users/:id request.
 * `name` and `email` are optional – only validated when present.
 * At least one field must be supplied so the update is not empty.
 *
 * @param {string} idParam - raw :id path parameter
 * @param {object} body    - parsed request body
 * @returns {string[]} all validation errors found
 */
function validateUpdateUser(idParam, body) {
  const errors = [
    ...validateId(idParam),
    ...validateName(body.name, /* optional= */ true),
    ...validateEmail(body.email, /* optional= */ true),
  ];

  const hasName  = body.name  !== undefined && body.name  !== null;
  const hasEmail = body.email !== undefined && body.email !== null;
  if (!hasName && !hasEmail) {
    errors.push('at least one of name or email must be provided');
  }

  return errors;
}

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
};

