 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a user `id` value (must be a positive integer).
 * Accepts both numbers and numeric strings (e.g. route params arrive as strings).
 *
 * @param {*}      value   - The value to test.
 * @param {string} field   - Field label used in error messages (default 'id').
 * @returns {string[]}     - Array of error messages; empty means valid.
 */
function validateId(value, field = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`${field} is required`);
    return errors;
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0 || String(value).trim() === '') {
    errors.push(`${field} must be a positive integer`);
  }

  return errors;
}

/**
 * Validate a `name` string (required, 1–100 characters).
 *
 * @param {*}      value   - The value to test.
 * @param {string} field   - Field label used in error messages (default 'name').
 * @returns {string[]}
 */
function validateName(value, field = 'name') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`${field} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${field} must be a string`);
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < 1) {
    errors.push(`${field} must be at least 1 character`);
  } else if (trimmed.length > 100) {
    errors.push(`${field} must be at most 100 characters`);
  }

  return errors;
}

/**
 * Validate an `email` string (required, valid format, max 254 characters).
 *
 * @param {*}      value   - The value to test.
 * @param {string} field   - Field label used in error messages (default 'email').
 * @returns {string[]}
 */
function validateEmail(value, field = 'email') {
  const errors = [];

  if (value === undefined || value === null) {
    errors.push(`${field} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${field} must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`${field} must be at most 254 characters`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${field} must be a valid email address`);
  }

  return errors;
}

/**
 * Run a set of field validators and send a 400 response if any fail.
 * Returns `true` when the request is invalid (response already sent),
 * `false` when everything is valid and the handler may continue.
 *
 * Usage:
 *   if (rejectIfInvalid(res, [
 *     ...validateName(req.body.name),
 *     ...validateEmail(req.body.email),
 *   ])) return;
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 * @returns {boolean}
 */
function rejectIfInvalid(res, errors) {
  if (errors.length === 0) return false;

  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

module.exports = { validateId, validateName, validateEmail, rejectIfInvalid };

