/**
 * Validation helper module.
 * Each validator returns an array of error strings (empty = valid).
 */

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a numeric id (URL param or query string – arrives as a string).
 * Accepts positive integers only.
 */
function validateId(value, fieldName = 'id') {
  const errors = [];
  if (value === undefined || value === null || value === '') {
    errors.push(`"${fieldName}" is required`);
    return errors; // no further checks possible
  }
  const num = Number(value);
  if (!Number.isInteger(num) || num <= 0) {
    errors.push(`"${fieldName}" must be a positive integer`);
  }
  return errors;
}

/**
 * Validate a name string (1–100 characters).
 */
function validateName(value, fieldName = 'name') {
  const errors = [];
  if (value === undefined || value === null) {
    errors.push(`"${fieldName}" is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string`);
    return errors;
  }
  const trimmed = value.trim();
  if (trimmed.length === 0) {
    errors.push(`"${fieldName}" must not be empty`);
  } else if (trimmed.length > 100) {
    errors.push(`"${fieldName}" must be at most 100 characters`);
  }
  return errors;
}

/**
 * Validate an email string (valid format, max 254 characters).
 */
function validateEmail(value, fieldName = 'email') {
  const errors = [];
  if (value === undefined || value === null) {
    errors.push(`"${fieldName}" is required`);
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push(`"${fieldName}" must be a string`);
    return errors;
  }
  if (value.length > 254) {
    errors.push(`"${fieldName}" must be at most 254 characters`);
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push(`"${fieldName}" must be a valid email address`);
  }
  return errors;
}

/**
 * Build and send a 400 response from an array of error strings.
 * Returns true so callers can do: if (sendErrors(res, errors)) return;
 */
function sendValidationErrors(res, errors) {
  if (errors.length === 0) return false;
  res.status(400).json({ error: 'Validation failed', details: errors });
  return true;
}

module.exports = { validateId, validateName, validateEmail, sendValidationErrors };
